#!/usr/bin/env python3
import base64,hashlib,os,sys
FILES={}
FILES['components/MessageBubble.tsx']=('','3ecdefa40da6f78c9e30fa3d67dcb436e5d4557a6f7395b84c840e2366cfba12',4451)
FILES['hooks/useChat.ts']=('','85c96c75c95c906d9b2a2486fc1b436d41cb83aafcdfe7ce396ce3c016d6323b',3617)
FILES['lib/types/vendor.ts']=('','aca7df0578e641531cb7c7b705a5b38ac8e15a5ef844256973bb9dabe7bc4233',7236)
def main():
    root=os.path.dirname(os.path.abspath(__file__))
    if not os.path.exists(os.path.join(root,'app/wedding/layout.tsx')):
        print("wrong dir");sys.exit(1)
    for p,(enc,sha,sz) in FILES.items():
        c=base64.b64decode(enc.encode()).decode()
        if hashlib.sha256(c.encode()).hexdigest()!=sha: print("HASH "+p);sys.exit(1)
        if len(c.encode())!=sz: print("SIZE "+p);sys.exit(1)
    for p,(enc,_,_) in FILES.items():
        c=base64.b64decode(enc.encode()).decode()
        full=os.path.join(root,p)
        os.makedirs(os.path.dirname(full),exist_ok=True)
        with open(full,"w") as f: f.write(c)
        print("WROTE "+p)
    os.remove(os.path.abspath(__file__))
    print('Done. git add -A && git commit -m feat: WhatsApp+Call buttons on drafted messages && git push')
if __name__=="__main__": main()